import type ActionButton from "../../support/actions/ActionButton.js";
import type ActionToggle from "../../support/actions/ActionToggle.js";
import type ListItem from "./ListItem.js";

/**
 * Specifies the style of the visibility toggle displayed in layer lists.
 *
 * @since 5.0
 * @see [BasemapLayerList.visibilityAppearance](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/#visibilityAppearance)
 * @see [CatalogLayerList.visibilityAppearance](https://developers.arcgis.com/javascript/latest/references/core/widgets/CatalogLayerList/#visibilityAppearance)
 * @see [LayerList.visibilityAppearance](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/#visibilityAppearance)
 */
export type VisibilityAppearance = "default" | "checkbox";

/**
 * A function used to filter which [ListItem](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/ListItem/) objects appear in the layer list.
 *
 * @param item - The list item to evaluate for inclusion.
 * @since 5.0
 * @see [BasemapLayerList.baseFilterPredicate](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/#baseFilterPredicate)
 * @see [BasemapLayerList.referenceFilterPredicate](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/#referenceFilterPredicate)
 * @see [CatalogLayerList.filterPredicate](https://developers.arcgis.com/javascript/latest/references/core/widgets/CatalogLayerList/#filterPredicate)
 * @see [LayerList.filterPredicate](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/#filterPredicate)
 */
export type FilterPredicate = (item: ListItem) => boolean;

/**
 * A function for customizing a list item as it is created in the layer lists.
 *
 * @param event - The event containing the list item to customize.
 * @since 5.0
 * @see [BasemapLayerList.baseListItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/#baseListItemCreatedFunction)
 * @see [BasemapLayerList.referenceListItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/#referenceListItemCreatedFunction)
 * @see [BasemapLayerListViewModel.baseListItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/BasemapLayerListViewModel/#baseListItemCreatedFunction)
 * @see [BasemapLayerListViewModel.referenceListItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/BasemapLayerListViewModel/#referenceListItemCreatedFunction)
 * @see [CatalogLayerList.listItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/CatalogLayerList/#listItemCreatedFunction)
 * @see [CatalogLayerListViewModel.listItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/CatalogLayerList/CatalogLayerListViewModel/#listItemCreatedFunction)
 * @see [LayerList.listItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/#listItemCreatedFunction)
 * @see [LayerListViewModel.listItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/LayerListViewModel/#listItemCreatedFunction)
 */
export type ListItemModifier = (event: ListItemModifierEvent) => void;

/**
 * The event object passed to a listItemCreatedFunction in the layer lists.
 * Provides access to the list item being created, allowing you to customize its properties, actions, panel content, or visibility before rendering.
 *
 * @since 5.0
 * @see [BasemapLayerList.baseListItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/#baseListItemCreatedFunction)
 * @see [BasemapLayerList.referenceListItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/#referenceListItemCreatedFunction)
 * @see [BasemapLayerListViewModel.baseListItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/BasemapLayerListViewModel/#baseListItemCreatedFunction)
 * @see [BasemapLayerListViewModel.referenceListItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/BasemapLayerListViewModel/#referenceListItemCreatedFunction)
 * @see [CatalogLayerList.listItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/CatalogLayerList/#listItemCreatedFunction)
 * @see [CatalogLayerListViewModel.listItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/CatalogLayerList/CatalogLayerListViewModel/#listItemCreatedFunction)
 * @see [LayerList.listItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/#listItemCreatedFunction)
 * @see [LayerListViewModel.listItemCreatedFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/LayerListViewModel/#listItemCreatedFunction)
 */
export interface ListItemModifierEvent {
  /**
   * The list item instance created by the LayerList. Modify this object to change the item's text, actions, panel content, or visibility.
   *
   * @since 5.0
   */
  item: ListItem;
}

/**
 * An action element that can be used in the layer lists.
 *
 * @since 5.0
 * @see [BasemapLayerList.triggerAction()](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/#triggerAction)
 * @see [BasemapLayerListViewModel.triggerAction()](https://developers.arcgis.com/javascript/latest/references/core/widgets/BasemapLayerList/BasemapLayerListViewModel/#triggerAction)
 * @see [CatalogLayerList.triggerAction()](https://developers.arcgis.com/javascript/latest/references/core/widgets/CatalogLayerList/#triggerAction)
 * @see [CatalogLayerListViewModel.triggerAction()](https://developers.arcgis.com/javascript/latest/references/core/widgets/CatalogLayerList/CatalogLayerListViewModel/#triggerAction)
 * @see [LayerList.triggerAction()](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/#triggerAction)
 * @see [LayerListViewModel.triggerAction()](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/LayerListViewModel/#triggerAction)
 * @see [TableList.triggerAction()](https://developers.arcgis.com/javascript/latest/references/core/widgets/TableList/#triggerAction)
 * @see [TableListViewModel.triggerAction()](https://developers.arcgis.com/javascript/latest/references/core/widgets/TableList/TableListViewModel/#triggerAction)
 */
export type Action = ActionButton | ActionToggle;

/**
 * Describes the current state of the list items in the [LayerListViewModel](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/LayerListViewModel/).
 *
 * @since 5.0
 * @see [LayerListViewModel.state](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/LayerListViewModel/#state)
 */
export type State = "ready" | "loading" | "disabled";